import Png from './components/PNG.vue';
import Medifarma from './components/MEDIFARMA.vue';
import Mtu from './components/MTU.vue';

const routes = [
    { path: '/png', component: Png },
    { path: '/medifarma', component: Medifarma },
    { path: '/mtu', component: Mtu },
    { path: '/', redirect: '/png' },
]

export default routes;